const body = $input.first().json.body;
const headers = $input.first().json.headers;

const token = $env.WIDGET_AUTH_TOKEN;
if (headers['x-widget-token'] !== token) {
  throw new Error('UNAUTHORIZED');
}

if (!body.message || body.message.length === 0 || body.message.length > 1000) {
  throw new Error('Invalid message');
}
if (!body.session_id) {
  throw new Error('session_id required');
}
if (body.consent !== true) {
  throw new Error('Consent required');
}

const ip = headers['x-forwarded-for'] || headers['x-real-ip'] || 'unknown';
const ipHash = ip.replace(/\./g, '-');

const wienTime = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Vienna' }));
const hour = wienTime.getHours();
const day = wienTime.getDay();
const isBusinessHours = (day >= 1 && day <= 5 && hour >= 8 && hour < 17);

return [{
  json: {
    session_id: body.session_id,
    message: body.message,
    ip_hash: ipHash,
    consent: body.consent,
    page_url: body.page_url || '',
    user_agent: headers['user-agent'] || '',
    is_business_hours: isBusinessHours,
    source_type: body.source_type || 'typed'
  }
}];

const validateData = $('Validate Input').first().json;

let historyRows = [];
try { historyRows = $('Load History').all(); } catch(e) { historyRows = []; }

let kbRows = [];
try { kbRows = $('Load Knowledge Base').all(); } catch(e) { kbRows = []; }

const history = historyRows.map(row => ({ role: row.json.role, content: row.json.content })).filter(m => m.role && m.content);

let kbContent = '';
let currentCategory = '';
for (const row of kbRows) {
  const entry = row.json;
  if (entry.category !== currentCategory) {
    currentCategory = entry.category;
    kbContent += '
--- ' + currentCategory.toUpperCase().replace(/_/g, ' ') + ' ---
';
  }
  kbContent += entry.title + ': ' + entry.content;
  if (entry.url) kbContent += ' (Mehr: ' + entry.url + ')';
  kbContent += '
';
}

const month = new Date().getMonth() + 1;
let season = 'fruehling';
if (month >= 6 && month <= 8) season = 'sommer';
else if (month >= 9 && month <= 11) season = 'herbst';
else if (month === 12 || month <= 2) season = 'winter';

let businessStatus = validateData.is_business_hours ? 'Büro geöffnet (Mo-Fr 08:00-17:00)' : 'Büro geschlossen';

const systemPrompt = `Du bist der RolloMax Berater - Sonnenschutz-Experte aus Wien.

KERNREGELN:
- Sie-Form, österreichisches Deutsch
- Verwende IMMER echte Umlaute: ä, ö, ü, ß (NICHT ae, oe, ue, ss)
- KEINE Emojis, KEINE Em-Dashes (--)
- Erste Nachricht: Kurz erwähnen dass du KI-gestützt bist

ANTWORT-STIL - EXTREM WICHTIG:
Der Nutzer ist kaufbereit und will schnelle, klare Infos. NICHT werben, NICHT selbst loben.

VERBOTEN:
- Sätze wie "Bei RolloMax bieten wir hervorragende..."
- "Wir haben tolle Lösungen..."
- Lange Fließtexte ohne Struktur
- Marketing-Sprache

STATTDESSEN:
- Direkt zur Sache, nützliche Infos zuerst
- Kurze Absätze (max 2-3 Sätze)
- Aufzählungen mit Bindestrich (-) für Optionen/Vorteile
- Bei Produktvergleichen: klare Gegenüberstellung

--- FIRST QUOTE LOGIK ---
Wenn der Nutzer nach Preisen fragt, AKTIV nach Maßen fragen!

1. FRAGEN die du stellen sollst:
- Breite und Höhe des Fensters (in cm)
- Anzahl der Fenster
- Bezirk (für Fahrkosten)

2. KALKULATION zeigen (sobald Maße bekannt):
- Material: [Preis aus Tabelle] x Anzahl
- Montage: 120 EUR/Stk (1-3), 96 EUR/Stk (4-10), 87 EUR/Stk (ab 10)
- Fahrkosten: 65 EUR (1020/1200) oder 110 EUR (andere Bezirke)
- GESAMT: Summe
- Mit Förderung (50%): ca. [Hälfte] EUR Eigenanteil

3. BEISPIEL Antwort bei Preisfrage ohne Maße:
"Für eine Schätzung brauche ich kurz:
- Breite und Höhe Ihrer Fenster (in cm)
- Anzahl der Fenster
- Ihr Bezirk in Wien

Dann kann ich Ihnen sofort einen Richtpreis nennen."

4. BEISPIEL Antwort mit Maßen (120x150cm, 3 Fenster, 1020):
"Ihre Schätzung für 3 Vorbaurollläden (120x150cm):

- Material: 3 x 464 EUR = 1.392 EUR
- Montage: 3 x 120 EUR = 360 EUR
- Fahrkosten: 65 EUR
- Gesamt: ca. 1.817 EUR

Mit Wiener Förderung (50%) wäre Ihr Eigenanteil ca. 909 EUR.

Für ein verbindliches Angebot: +43 1 212 2446"
--- ENDE FIRST QUOTE LOGIK ---

BEISPIEL GUTE ANTWORT (allgemein):
"Für Ihre Terrasse gibt es zwei Optionen:

- Gelenkarmmarkise: klassisch, günstig, ideal bis 4m Ausfall
- Kassettenmarkise: Stoff geschützt, langlebiger, bis 6m möglich

Beide mit Motor nachrüstbar. Welche Breite brauchen Sie ungefähr?"

CONVERSION-FOKUS:
- Nach 2-3 Infos: konkrete Frage stellen ODER Termin anbieten
- Telefon: +43 1 212 2446
- Adresse: Leopoldsgasse 4, 1020 Wien

JAHRESZEIT: ${season}
GESCHÄFTSZEIT: ${businessStatus}

THEMEN: Nur Sonnenschutz, Fenster, Montage. Sonst höflich ablehnen.

ANTWORT-FORMAT:
<<<RESPONSE_JSON>>>
{"reply":"...","intent":"general","lead_data":null,"should_notify_team":false,"urgency":"low"}
<<<END_RESPONSE_JSON>>>

WISSENSBASIS:
${kbContent}`;

const messages = [...history];
messages.push({ role: 'user', content: validateData.message });

return [{
  json: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1000,
    system: systemPrompt,
    messages: messages,
    _session_id: validateData.session_id,
    _user_message: validateData.message,
    _is_business_hours: validateData.is_business_hours,
    _source_type: validateData.source_type
  }
}];

const input = $input.first().json;
const payload = $('Build Claude Payload').first().json;

let responseText = '';
let parsed = null;

if (input.content && input.content[0]) {
  responseText = input.content[0].text;
  const jsonMatch = responseText.match(/<<<RESPONSE_JSON>>>([\s\S]*?)<<<END_RESPONSE_JSON>>>/);
  if (jsonMatch) {
    try { parsed = JSON.parse(jsonMatch[1].trim()); } catch(e) {}
  }
}

if (!parsed) {
  parsed = {
    reply: responseText || 'Entschuldigung, ich konnte Ihre Anfrage nicht verarbeiten. Bitte kontaktieren Sie uns unter +43 1 212 2446.',
    intent: 'general',
    lead_data: null,
    should_notify_team: false,
    urgency: 'low'
  };
}

return [{
  json: {
    reply: parsed.reply,
    session_id: payload._session_id,
    user_message: payload._user_message,
    intent: parsed.intent || 'general',
    has_lead_data: !!parsed.lead_data,
    lead_data: parsed.lead_data,
    should_notify_team: parsed.should_notify_team || false,
    urgency: parsed.urgency || 'low',
    source_type: payload._source_type || 'typed'
  }
}];
